CREATE INDEX ON entity_pool_map (pool_hash_id);
ANALYZE entity_pool_map;

COPY (
  SELECT
    epm.entity_id,
    es.epoch_no,
    COUNT(DISTINCT es.pool_id) AS active_pools,
    SUM(es.amount)             AS total_stake,
    COUNT(*)                   AS delegation_count
  FROM epoch_stake es
  JOIN entity_pool_map epm ON epm.pool_hash_id = es.pool_id
  GROUP BY epm.entity_id, es.epoch_no
  ORDER BY epm.entity_id, es.epoch_no
) TO '/tmp/entity_stake_history.csv' WITH CSV HEADER;
